-- =============================================================================
-- Seed: seed.market.sql
-- Purpose : Synthetic mock-mirror market data for the dashboard endpoints.
-- Source  : dashboard_client_web/apis/getDashboardSnapshot.mock.api.ts
--           + getDashboardHistory.mock.api.ts (deterministic LCG candles).
-- Note    : No secrets. Idempotent via ON CONFLICT upserts. NOT auto-applied.
-- =============================================================================

-- ---------------------------------------------------------------------------
-- market_snapshots (22 items)
-- ---------------------------------------------------------------------------
ON CONFLICT (category, label) DO UPDATE SET
    ticker = EXCLUDED.ticker, exchange = EXCLUDED.exchange, value = EXCLUDED.value,
    change_absolute = EXCLUDED.change_absolute, change_percent = EXCLUDED.change_percent,
    as_of = EXCLUDED.as_of, revalidate_seconds = EXCLUDED.revalidate_seconds,
    fetched_at = EXCLUDED.fetched_at, updated_at = CURRENT_TIMESTAMP;

-- ---------------------------------------------------------------------------
-- market_history (interval 1d, 250 daily candles per item)
-- ---------------------------------------------------------------------------
ON CONFLICT (label, interval, bar_time) DO UPDATE SET
    open = EXCLUDED.open, high = EXCLUDED.high, low = EXCLUDED.low,
    close = EXCLUDED.close, volume = EXCLUDED.volume, updated_at = CURRENT_TIMESTAMP;
